// // This module implements a 2-bit Johnson counter that resets to 2'b11 on positive edge of clk
module johnson_counter_2 
(
  input rst,
  input clk,

  output reg [1:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 2'b00;
    end 
	else 
	begin
      count <= {count[0], ~count[1]};
    end
  end

endmodule
